#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

// Structure to represent a graph edge
typedef struct Edge {
    int src, dest, weight;
} Edge;

// Structure to represent a graph
typedef struct Graph {
    int V, E;
    Edge* edge;
} Graph;

// Function to create a graph
Graph* createGraph(int V, int E) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    graph->V = V;
    graph->E = E;
    graph->edge = (Edge*) malloc(E * sizeof(Edge));
    return graph;
}

// Function to find the shortest distance using Dijkstra's Algorithm
void dijkstra(Graph* graph, int src) {
    int* dist = (int*) malloc(graph->V * sizeof(int));
    for (int i = 0; i < graph->V; i++)
        dist[i] = INT_MAX;
    dist[src] = 0;

    // Create a priority queue to store vertices to be processed
    int* pq = (int*) malloc(graph->V * sizeof(int));
    int pqSize = 0;
    pq[pqSize++] = src;

    while (pqSize > 0) {
        int u = pq[0];
        for (int i = 1; i < pqSize; i++)
            if (dist[pq[i]] < dist[u])
                u = pq[i];
        pqSize--;
        for (int i = 0; i < pqSize; i++)
            if (pq[i] == u)
                pq[i] = pq[pqSize];

        for (int i = 0; i < graph->E; i++) {
            int v = graph->edge[i].dest;
            int w = graph->edge[i].weight;
            if (dist[u] != INT_MAX && dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                pq[pqSize++] = v;
            }
        }
    }

    printf("Shortest distances from vertex %d:\n", src);
    for (int i = 0; i < graph->V; i++)
        printf("Vertex %d: %d\n", i, dist[i]);
}

int main() {
    int V, E;
    scanf("%d %d", &V, &E);
    Graph* graph = createGraph(V, E);
    for (int i = 0; i < E; i++)
        scanf("%d %d %d", &graph->edge[i].src, &graph->edge[i].dest, &graph->edge[i].weight);
    int src;
    scanf("%d", &src);
    dijkstra(graph, src);
    return 0;
}

